+		parts = append(parts, "gh:"+row.GitHubLogin)
+	}
+	if row.Website != "" {
+		parts = append(parts, row.Website)
+	}
+	if row.Bio != "" {
+		parts = append(parts, trimForTable(row.Bio))
+	}
+	return strings.Join(parts, " | ")
